mapper.select:
SELECT count(*)
FROM hm_query.fact_shipments fs
LEFT JOIN hm_query.dim_carrier dca ON fs.carrier = dca.carrier_code
LEFT JOIN hm_query.dim_geography dg ON fs.destination_pincode = dg.pincode

    AND fs.order_id = #{orderId}
    AND fs.customer_id = #{customerId}
    AND fs.carrier = #{carrier}
    AND fs.shipping_method = #{shippingMethod}
    AND fs.state_id = #{stateId}
    AND (
        fs.order_id LIKE CONCAT('%', #{q}, '%')
        OR fs.tracking_number LIKE CONCAT('%', #{q}, '%')
        OR fs.customer_name LIKE CONCAT('%', #{q}, '%')
        OR dca.carrier_name LIKE CONCAT('%', #{q}, '%')
    )

SELECT fs.id, fs.order_id as "orderId", fs.order_number as "orderNumber", fs.customer_id as "customerId", fs.customer_name as "customerName", fs.carrier, dca.carrier_name as "carrierName", fs.tracking_number as "trackingNumber", fs.shipping_method as "shippingMethod", fs.state_id as "stateId", fs.flow_id as "flowId", fs.delivery_attempts as "deliveryAttempts", fs.estimated_delivery_date as "estimatedDeliveryDate", fs.actual_delivery_date as "actualDeliveryDate", fs.current_location as "currentLocation", dg.city as "destinationCity", dg.state as "destinationState", fs.created_time as "createdAt" FROM hm_query.fact_shipments fs LEFT JOIN hm_query.dim_carrier dca ON fs.carrier = dca.carrier_code LEFT JOIN hm_query.dim_geography dg ON fs.destination_pincode = dg.pincode
AND fs.order_id = #{orderId} AND fs.customer_id = #{customerId} AND fs.carrier = #{carrier} AND fs.shipping_method = #{shippingMethod} AND fs.state_id = #{stateId} AND ( fs.order_id LIKE CONCAT('%', #{q}, '%') OR fs.tracking_number LIKE CONCAT('%', #{q}, '%') OR fs.customer_name LIKE CONCAT('%', #{q}, '%') OR dca.carrier_name LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.fact_shipments
WHERE carrier = #{carrier}
AND state_id = #{stateId}
